def init_session_state():
    """Initialize all Streamlit session state variables on first load."""
    defaults = {
        "screen":           "welcome",   # "welcome" or "chat"
        "student_id":       "",
        "language":         "auto",      # "auto", "en", or "es"
        "difficulty":       "medium",
        "messages":         [],          # list of {role, content, type}
        "quiz_state":       None,        # None or dict when quiz is active
        "session_start":    None,        # time.time() at session start
        "session_score":    0,
        "session_max":      0,
        "session_calls":    0,
        "session_topics":   [],
        "session_standards": [],
        "current_lang":     "en",
        "num_questions":    3,
        "session_ended":    False,
        "usage_saved":      False,
        "selected_standard": None,
        "selected_skill":    None,
        "selected_mode":     "Challenge me",
        "used_connection_fields": [],
        "session_semillas":  0,
        "retry_standard":    None,
        "awarded_showed_up": False,
    }
    for key, val in defaults.items():
        if key not in st.session_state:
            st.session_state[key] = val


init_session_state()


